import EventCard from "@/components/EventCard";

async function getEvents() {
  try {
    const res = await fetch("https://qevent-backend.labs.crio.do/events", {
      cache: "no-store",
    });
    if (!res.ok) {
      throw new Error("Failed to fetch events");
    }
    return await res.json();
  } catch (error) {
    console.error("Error fetching events:", error);
    return [];
  }
}

export default async function Events() {
  const events = await getEvents();

  return (
    <div className="w-full">
      <h1 className="text-5xl font-bold max-sm:text-3xl bg-gradient-to-br from-orange-400 to-teal-600 bg-clip-text text-transparent mx-4 mt-8 mb-8">
        All Events
      </h1>

      {events.length > 0 ? (
        <div className="flex flex-wrap items-center justify-around mb-32">
          {events.map((eventData) => (
            <EventCard key={eventData._id || eventData.id} eventData={eventData} />
          ))}
        </div>
      ) : (
        <div className="flex items-center justify-center min-h-screen">
          <p className="text-xl text-gray-600">No events found</p>
        </div>
      )}
    </div>
  );
}

