    const res = await fetch("https://qevent-backend.labs.crio.do/tags", {
      cache: "no-store",
    });
    if (!res.ok) {
      throw new Error("Failed to fetch tags");
    }
    return await res.json();
  } catch (error) {
    console.error("Error fetching tags:", error);
    return [];
  }
}

export default async function Tags() {
  const tags = await getTags();

  return (
    <div className="w-full">
      <h1 className="text-5xl font-bold max-sm:text-3xl bg-gradient-to-br from-orange-400 to-teal-600 bg-clip-text text-transparent mx-4 mt-8 mb-8">
        All Tags
      </h1>

      {tags.length > 0 ? (
        <div className="flex flex-wrap gap-4 mx-4 mb-32">
          {tags.map((tagData) => (
            <Tag key={tagData._id || tagData.name} text={tagData.name} />
          ))}
        </div>
      ) : (
        <div className="flex items-center justify-center min-h-screen">
          <p className="text-xl text-gray-600">No tags found</p>
        </div>
      )}
    </div>
  );
}

