"use client";

import EventCard from "@/components/EventCard";
import { useSearchParams } from "next/navigation";
import { useEffect, useState } from "react";

export default function Events() {
  const searchParams = useSearchParams();
  const artistFilter = searchParams.get("artist");
  const tagFilter = searchParams.get("tag");
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filteredEvents, setFilteredEvents] = useState([]);

  useEffect(() => {
    const fetchEvents = async () => {
      try {
        const res = await fetch("https://qevent-backend.labs.crio.do/events", {
          cache: "no-store",
        });
        if (!res.ok) {
          throw new Error("Failed to fetch events");
        }
        const data = await res.json();
        setEvents(data);

        // Filter events based on artist and/or tag parameters
        let filtered = data;

        if (artistFilter) {
          filtered = filtered.filter(
            (event) => event.artist.toLowerCase() === artistFilter.toLowerCase()
          );
        }

        if (tagFilter) {
          filtered = filtered.filter(
            (event) =>
              event.tags &&
              event.tags.some((t) => t.toLowerCase() === tagFilter.toLowerCase())
          );
        }

        setFilteredEvents(filtered);
      } catch (error) {
        console.error("Error fetching events:", error);
        setEvents([]);
        setFilteredEvents([]);
      } finally {
        setLoading(false);
      }
    };

    fetchEvents();
  }, [artistFilter, tagFilter]);

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <p className="text-xl text-gray-600">Loading events...</p>
      </div>
    );
  }

  const getHeading = () => {
    if (artistFilter && tagFilter) {
      return `Events by ${artistFilter} with tag ${tagFilter}`;
    } else if (artistFilter) {
      return `Events by ${artistFilter}`;
    } else if (tagFilter) {
      return `Events with tag ${tagFilter}`;
    }
    return "All Events";
  };

  return (
    <div className="w-full">
      <h1 className="text-5xl font-bold max-sm:text-3xl bg-gradient-to-br from-orange-400 to-teal-600 bg-clip-text text-transparent mx-4 mt-8 mb-8">
        {getHeading()}
      </h1>

      {filteredEvents.length > 0 ? (
        <div className="flex flex-wrap items-center justify-around mb-32">
          {filteredEvents.map((eventData) => (
            <EventCard key={eventData._id || eventData.id} eventData={eventData} />
          ))}
        </div>
      ) : (
        <div className="flex items-center justify-center min-h-screen">
          <p className="text-xl text-gray-600">
            No events found
            {artistFilter && ` for artist ${artistFilter}`}
            {tagFilter && ` with tag ${tagFilter}`}
          </p>
        </div>
      )}
    </div>
  );
}

