import Link from "next/link";

async function getEvent(eventId) {
  try {
    const res = await fetch(
      `https://qevent-backend.labs.crio.do/events/${eventId}`,
      {
        cache: "no-store",
      }
    );
    if (!res.ok) {
      throw new Error("Failed to fetch event");
    }
    return await res.json();
  } catch (error) {
    console.error("Error fetching event:", error);
    return null;
  }
}

export default async function EventDetails({ params }) {
  const { eventId } = params;
  const event = await getEvent(eventId);

  if (!event) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <h1 className="text-5xl font-bold text-gray-600 mb-4">Event Not Found</h1>
          <p className="text-lg text-gray-500 mb-8">
            Sorry, we couldn't find the event you're looking for.
          </p>
          <Link
            href="/events"
            className="bg-gradient-to-r from-orange-400 to-teal-600 text-white px-6 py-3 rounded-md font-medium hover:opacity-70"
          >
            Back to Events
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="w-full py-12 px-4 md:px-12">
      <div className="max-w-7xl mx-auto">
        {/* Back Button */}
        <Link
          href="/events"
          className="text-orange-500 hover:text-teal-600 font-semibold mb-8 inline-block transition-colors"
        >
          ← Back to Events
        </Link>

        {/* Main Content - Two Column Layout */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-start">
          {/* Left Column - Event Image */}
          <div className="flex justify-center">
            <img
              src={event.image}
              alt={event.name}
              className="w-full max-w-md h-auto object-cover rounded-lg shadow-2xl"
            />
          </div>

          {/* Right Column - Event Details */}
          <div className="flex flex-col justify-start">
            {/* Event Title */}
            <h1 className="text-5xl font-bold text-orange-500 mb-2">
              {event.name}
            </h1>

            {/* Location */}
            <p className="text-gray-600 text-lg mb-1">{event.location}</p>

            {/* Artist */}
            <p className="text-orange-500 font-semibold text-lg mb-6">
              {event.artist}
            </p>

            {/* Tags */}
            {event.tags && event.tags.length > 0 && (
              <div className="flex flex-wrap gap-3 mb-8">
                {event.tags.map((tag) => (
                  <Tag key={tag} text={tag} />
                ))}
              </div>
            )}

            {/* Description */}
            <p className="text-gray-700 text-base leading-relaxed mb-8">
              {event.description ||
                "Experience an unforgettable evening with live performances and exceptional entertainment."}
            </p>

            {/* Price and Button Section */}
            <div className="flex items-center justify-between">
              {/* Price */}
              <div>
                <p className="text-5xl font-bold text-orange-500">
                  {event.price > 0 ? `$${event.price.toLocaleString()}` : "FREE"}
                </p>
              </div>

              {/* Buy Tickets Button */}
              <button className="bg-red-500 hover:bg-red-600 text-white px-6 py-3 rounded-md font-medium transition-colors">
                Buy Tickets
              </button>
            </div>

            {/* Additional Info */}
            {(event.date || event.time || event.eventType || event.capacity) && (
              <div className="mt-12 pt-8 border-t border-gray-200">
                <div className="grid grid-cols-2 gap-6">
                  {event.date && (
                    <div>
                      <p className="text-gray-500 text-sm font-semibold mb-2">
                        DATE
                      </p>
                      <p className="text-gray-800">
                        {new Date(event.date).toDateString()}
                      </p>
                    </div>
                  )}
                  {event.time && (
                    <div>
                      <p className="text-gray-500 text-sm font-semibold mb-2">
                        TIME
                      </p>
                      <p className="text-gray-800">{event.time}</p>
                    </div>
                  )}
                  {event.eventType && (
                    <div>
                      <p className="text-gray-500 text-sm font-semibold mb-2">
                        EVENT TYPE
                      </p>
                      <p className="text-gray-800">{event.eventType}</p>
                    </div>
                  )}
                  {event.capacity && (
                    <div>
                      <p className="text-gray-500 text-sm font-semibold mb-2">
                        CAPACITY
                      </p>
                      <p className="text-gray-800">{event.capacity}</p>
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

