import Tag from "@/components/Tag";
import Link from "next/link";

async function getEvent(eventId) {
  try {
    const res = await fetch(
      `https://qevent-backend.labs.crio.do/events/${eventId}`,
      {
        cache: "no-store",
      }
    );
    if (!res.ok) {
      throw new Error("Failed to fetch event");
    }
    return await res.json();
  } catch (error) {
    console.error("Error fetching event:", error);
    return null;
  }
}

export default async function EventDetails({ params }) {
  const { eventId } = params;
  const event = await getEvent(eventId);

  if (!event) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <h1 className="text-5xl font-bold text-gray-600 mb-4">Event Not Found</h1>
          <p className="text-lg text-gray-500 mb-8">
            Sorry, we couldn't find the event you're looking for.
          </p>
          <Link
            href="/events"
            className="bg-gradient-to-r from-orange-400 to-teal-600 text-white px-6 py-3 rounded-md font-medium hover:opacity-70"
          >
            Back to Events
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="w-full py-8">
      <div className="max-w-6xl mx-auto px-4">
        {/* Back Button */}
        <Link
          href="/events"
          className="text-orange-500 hover:text-teal-600 font-semibold mb-8 inline-block transition-colors"
        >
          ← Back to Events
        </Link>

        {/* Event Header */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-12">
          {/* Event Image */}
          <div className="flex items-center justify-center">
            <img
              src={event.image}
              alt={event.name}
              className="w-full h-full object-cover rounded-lg shadow-lg"
            />
          </div>

          {/* Event Basic Info */}
          <div className="flex flex-col justify-center">
            <h1 className="text-5xl font-bold bg-gradient-to-r from-orange-400 to-teal-600 bg-clip-text text-transparent mb-4">
              {event.name}
            </h1>

            <div className="mb-6">
              <p className="text-2xl font-semibold text-gray-700 mb-2">
                Artist: {event.artist}
              </p>
            </div>

            <div className="mb-6">
              <p className="text-gray-600 mb-2">
                <span className="font-semibold">Date & Time:</span>
              </p>
              <p className="text-lg">
                {new Date(event.date).toDateString()} at {event.time}
              </p>
            </div>

            <div className="mb-6">
              <p className="text-gray-600 mb-2">
                <span className="font-semibold">Location:</span>
              </p>
              <p className="text-lg">{event.location}</p>
            </div>

            <div className="mb-6">
              <p className="text-gray-600 mb-2">
                <span className="font-semibold">Price:</span>
              </p>
              <p className="text-3xl font-bold bg-gradient-to-r from-orange-400 to-teal-600 bg-clip-text text-transparent">
                {event.price > 0 ? `$${event.price.toLocaleString()}` : "FREE"}
              </p>
            </div>

            {/* Tags */}
            {event.tags && event.tags.length > 0 && (
              <div className="mb-6">
                <p className="text-gray-600 mb-3">
                  <span className="font-semibold">Tags:</span>
                </p>
                <div className="flex flex-wrap gap-3">
                  {event.tags.map((tag) => (
                    <Tag key={tag} text={tag} />
                  ))}
                </div>
              </div>
            )}

            {/* CTA Button */}
            <button className="bg-gradient-to-r from-orange-400 to-teal-600 text-white px-8 py-3 rounded-md font-medium hover:opacity-70 transition-opacity w-full md:w-auto">
              Get Tickets
            </button>
          </div>
        </div>

        {/* Event Description */}
        {event.description && (
          <div className="bg-slate-50 rounded-lg p-8 mb-12">
            <h2 className="text-3xl font-bold mb-4 text-gray-800">About Event</h2>
            <p className="text-lg text-gray-700 leading-relaxed">
              {event.description}
            </p>
          </div>
        )}

        {/* Additional Event Details */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="bg-slate-100 rounded-lg p-6">
            <h3 className="text-xl font-bold mb-2 text-gray-800">Event Type</h3>
            <p className="text-gray-600">{event.eventType || "Concert"}</p>
          </div>

          <div className="bg-slate-100 rounded-lg p-6">
            <h3 className="text-xl font-bold mb-2 text-gray-800">Duration</h3>
            <p className="text-gray-600">{event.duration || "TBA"}</p>
          </div>

          <div className="bg-slate-100 rounded-lg p-6">
            <h3 className="text-xl font-bold mb-2 text-gray-800">Capacity</h3>
            <p className="text-gray-600">{event.capacity || "TBA"}</p>
          </div>
        </div>
      </div>
    </div>
  );
}

