toolUseResult.content:
"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";

export default function CreateEvent() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [formData, setFormData] = useState({
    name: "",
    artist: "",
    location: "",
    date: "",
    time: "",
    price: 0,
    description: "",
    tags: "",
  });
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    // If user is not authenticated, redirect to events page
    if (status === "unauthenticated") {
      router.push("/events");
    }
  }, [status, router]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleEventCreate = async (e) => {
    e.preventDefault();
    setIsLoading(true);

    try {
      // Generate random image number between 1 and 99
      const randomImageNumber = Math.floor(Math.random() * 99) + 1;
      const imageUrl = `https://picsum.photos/400/300?random=${randomImageNumber}`;

      // Parse tags from comma-separated string
      const tagsArray = formData.tags
        .split(",")
        .map((tag) => tag.trim())
        .filter((tag) => tag.length > 0);

      // Create event payload
      const eventPayload = {
        name: formData.name,
        artist: formData.artist,
        location: formData.location,
        date: formData.date,
        time: formData.time,
        price: parseFloat(formData.price) || 0,
        description: formData.description,
        tags: tagsArray,
        image: imageUrl,
      };

      console.log("Event Payload:", eventPayload);

      // Make POST request to create event
      const response = await fetch(
        "https://qevent-backend.labs.crio.do/events",
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify(eventPayload),
        }
      );

      console.log("Response Status:", response.status);
      const responseData = await response.json();
      console.log("Response Data:", responseData);

      if (response.status === 201) {
        // Event created successfully
        console.log("Event created successfully!");
        // Redirect to events page
        router.push("/events");
      } else {
        throw new Error("Failed to create event");
      }
    } catch (error) {
      console.error("Error creating event:", error);
      alert("Event creation failed");
      setIsLoading(false);
    }
  };

  // Show loading state while checking authentication
  if (status === "loading") {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <p className="text-xl text-gray-600">Loading...</p>
      </div>
    );
  }

  // Only render if user is authenticated
  if (status !== "authenticated") {
    return null;
  }

  return (
    <div className="w-full py-12 px-4 md:px-12">
      <div className="max-w-4xl mx-auto">
        <h1 className="text-5xl font-bold max-sm:text-3xl bg-gradient-to-br from-orange-400 to-teal-600 bg-clip-text text-transparent mb-8">
          Create Event
        </h1>

        <div className="bg-white rounded-lg shadow-lg p-8">
          <form onSubmit={handleEventCreate} className="space-y-6">
            {/* Event Name */}
            <div>
              <label className="block text-lg font-semibold text-gray-700 mb-2">
                Event Name *
              </label>
              <input
                type="text"
                name="name"
                value={formData.name}
                onChange={handleInputChange}
                placeholder="Enter event name"
                required
                className="w-full px-4 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-400"
              />
            </div>

            {/* Artist */}
            <div>
              <label className="block text-lg font-semibold text-gray-700 mb-2">
                Artist *
              </label>
              <input
                type="text"
                name="artist"
                value={formData.artist}
                onChange={handleInputChange}
                placeholder="Enter artist name"
                required
                className="w-full px-4 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-400"
              />
            </div>

            {/* Location */}
            <div>
              <label className="block text-lg font-semibold text-gray-700 mb-2">
                Location *
              </label>
              <input
                type="text"
                name="location"
                value={formData.location}
                onChange={handleInputChange}
                placeholder="Enter event location"
                required
                className="w-full px-4 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-400"
              />
            </div>

            {/* Date */}
            <div>
              <label className="block text-lg font-semibold text-gray-700 mb-2">
                Date *
              </label>
              <input
                type="date"
                name="date"
                value={formData.date}
                onChange={handleInputChange}
                required
                className="w-full px-4 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-400"
              />
            </div>

            {/* Time */}
            <div>
              <label className="block text-lg font-semibold text-gray-700 mb-2">
                Time *
              </label>
              <input
                type="time"
                name="time"
                value={formData.time}
                onChange={handleInputChange}
                required
                className="w-full px-4 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-400"
              />
            </div>

            {/* Price */}
            <div>
              <label className="block text-lg font-semibold text-gray-700 mb-2">
                Price (Leave 0 for free)
              </label>
              <input
                type="number"
                name="price"
                value={formData.price}
                onChange={handleInputChange}
                placeholder="Enter ticket price"
                step="0.01"
                min="0"
                className="w-full px-4 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-400"
              />
            </div>

            {/* Tags */}
            <div>
              <label className="block text-lg font-semibold text-gray-700 mb-2">
                Tags (comma-separated)
              </label>
              <input
                type="text"
                name="tags"
                value={formData.tags}
                onChange={handleInputChange}
                placeholder="e.g. Music, Jazz, Live"
                className="w-full px-4 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-400"
              />
            </div>

            {/* Description */}
            <div>
              <label className="block text-lg font-semibold text-gray-700 mb-2">
                Description
              </label>
              <textarea
                name="description"
                value={formData.description}
                onChange={handleInputChange}
                placeholder="Enter event description"
                rows="4"
                className="w-full px-4 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-400"
              />
            </div>

            {/* Submit Button */}
            <button
              type="submit"
              disabled={isLoading}
              className="w-full bg-gradient-to-r from-orange-400 to-teal-600 text-white px-6 py-3 rounded-md font-medium hover:opacity-70 transition-opacity disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {isLoading ? "Creating Event..." : "Create Event"}
            </button>
          </form>

          <p className="mt-6 text-center text-gray-600">
            Logged in as: <span className="font-semibold">{session?.user?.email}</span>
          </p>
        </div>
      </div>
    </div>
  );
}

